use std::collections::HashMap;
use std::error::Error;
use std::fmt;

struct LogEntry { 
    timestamp: String,
    message: String,
}

impl fmt::Display for LogEntry {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "[{}] {}", self.timestamp, self.message)
    }
}

fn process_log_chunk(file_name: &str, content: &str) -> Result<LogEntry, Box<dyn Error>> {
    if file_name.is_empty() || content.is_empty() {
        return Err("File name or content cannot be empty".into());
    }

    let timestamp = format!("{}:0", file_name);
    let message = content.trim().to_string();

    if message.len() > 256 {
        return Err("Message too long for simulation".into());
    }

    Ok(LogEntry { timestamp, message })
}

fn aggregate_logs(file_data: &[(String, String)]) -> HashMap<String, LogEntry> {
    let mut results = HashMap::new();
    for (name, content) in file_data {
        match process_log_chunk(name, content) {
            Ok(entry) => { 
                results.insert(format!("processed{}", name), entry);
            },
            Err(e) => {
                eprintln!("Skipping file {} due to error: {}", name, e);
            }
        }
    }
    results
}

fn main() -> Result<(), Box<dyn Error>> {
    let files_to_test = vec![
        (String::from("auth.log"), String::from("User logged in successfully.")),
        (String::from("system.log"), String::from("Kernel initialized on machine X."))
    ];

    let processed = aggregate_logs(&files_to_test);

    println!("--- Aggregation Results ---n");
    for entry in processed.values() {
        println!("{}", entry);
    }

    Ok(())
}

