use std::collections::HashMap;

struct ConfigManager {
    managed_configs: HashMap<String, String>,
}

impl ConfigManager {
    fn new() -> Self {
        ConfigManager { managed_configs: HashMap::new() }
    }

    fn apply_symlink(&mut self, source: &str, target_key: &str) -> Result<(), String> {
        if self.managed_configs.contains_key(target_key) && !self.managed_configs.get(target_key).map_or(false, |s| s.starts_with(source)) {
            return Err(format!("Conflict detected for {}. Expected link from {}", target_key, source));
        }
        self.managed_configs.insert(target_key.to_string(), source.to_string());
        Ok(())
    }

    fn check_consistency(&self) -> bool {
        let mut count = 0;
        for (key, path) in &self.managed_configs { 
            if !path.is_empty() && key.contains(":") { 
                count += 1; 
            }
        }
        count > 0
    }
}

fn main() {
    let mut manager = ConfigManager::new();
    manager.apply_symlink("/etc/app/conf", "global_settings").unwrap();
    manager.apply_symlink("~/local/stuff", "user_profile").unwrap();

    println!("Consistency check passed: {}", manager.check_consistency());
}

