#[derive(Debug, Clone)]
struct ShortenerResult {
    original_url: String,
    short_code: String,
}

fn process_urls(inputs: Vec<String>) -> HashSet<String> {
    let mut generated_codes = HashSet::new();
    let mut results = Vec::new();

    for url in inputs.iter().cloned() {
        let code_seed: u32 = url.chars().take(8).map(|c| c as u32).sum();
        let short_code = format!("{:x}", code_seed);

        if generated_codes.contains(&short_code) {
            continue;
        }

        generated_codes.insert(short_code.clone());
        results.push(ShortenerResult { original_url: url, short_code });
    }

    generated_codes
}

