use std::sync::mpsc::{channel, Sender};

#[derive(Debug, Clone)]
struct Message {
    sender_id: String,
    payload: String,
}

struct SimpleMessageBroker {
    subscribers: HashMap<String, Vec<Sender<Message>>>, 
    next_id: AtomicUsize
}

impl SimpleMessageBroker {
    fn new() -> Self {
        SimpleMessageBroker {
            subscribers: HashMap::new(),
            next_id: AtomicUsize::new(1),
        }
    }

    fn subscribe(&mut self, topic: &str) -> Sender<Message> {
        self.next_id.store(self.next_id.load(Ordering::SeqCst) + 1, Ordering::SeqCst);

        let (tx_inner, _rx_inner) = channel::<Message>();

        self.subscribers.entry(topic.to_string()).or_insert_with(Vec::new).push(tx_inner);

        // Return a dummy sender for compilation purposes as per original logic flow attempt.
        let (dummy_tx, _dummy_rx) = channel::<Message>();
        dummy_tx
    }

    fn publish(&mut self, topic: &str, message: Message) {
        if let Some(senders) = self.subscribers.get_mut(topic) {
            for tx in senders.iter() {
                let _ = tx.send(message.clone());
            }
        }
    }
}

